// Pass a cancellation signal into fn so it can self-terminate
function withAgentDispatchLock<T>(agentName: string, fn: (signal: AbortSignal) => Promise<T>): Promise<T> {
  let resolve: () => void;
  const next = new Promise<void>((r) => { resolve = r; });
  const prev = _agentDispatchQueues.get(agentName) || Promise.resolve();
  _agentDispatchQueues.set(agentName, next);
  return prev.then(async () => {
    _dispatchStartTimes.set(agentName, Date.now());
    const abortController = new AbortController();
    let forceReleased = false;
    const safety = setTimeout(() => {
      log.error(`[${agentName}] dispatch lock force-released after ${DISPATCH_LOCK_TIMEOUT_MS / 1000}s`);
      forceReleased = true;
      abortController.abort(); // Signal fn() to stop at its next checkpoint
      stopInference(agentName);
      _dispatchStartTimes.delete(agentName);
      resolve!();
    }, DISPATCH_LOCK_TIMEOUT_MS);
    try {
      return await fn(abortController.signal); // fn checks signal.aborted before each await
    } catch (err) {
      if (forceReleased) {
        log.warn(`[${agentName}] swallowing post-force-release error: ${err}`);
        return undefined as T;
      }
      throw err;
    } finally {
      clearTimeout(safety);
      _dispatchStartTimes.delete(agentName);
      if (!forceReleased) resolve!();
      if (_agentDispatchQueues.get(agentName) === next) {
        _agentDispatchQueues.delete(agentName);
      }
    }
  });
}

